const tgData = $('Telegram Trigger').item.json;
const msg = tgData.message || {};
return {
  json: {
    chat_id: String(msg.chat?.id || ''),
    message_id: msg.message_id || 0,
    user_text: msg.caption || 'Analiza esta imagen.',
    has_image: true,
    first_name: msg.from?.first_name || ''
  }
};

const msg = $input.item.json.message || {};
const voice = msg.voice || msg.audio;
const userText = msg.text || msg.caption || "";

// If it is audio/voice without text, mark it so we can handle gracefully
if (!userText && voice) {
  return {
    json: {
      chat_id: String(msg.chat?.id || ""),
      message_id: msg.message_id || 0,
      user_text: "El usuario envio un audio pero no pude procesarlo. Por favor pide que envie un mensaje de texto.",
      has_image: false,
      first_name: msg.from?.first_name || ""
    }
  };
}

return {
  json: {
    chat_id: String(msg.chat?.id || ""),
    message_id: msg.message_id || 0,
    user_text: userText,
    has_image: false,
    first_name: msg.from?.first_name || ""
  }
};

// Get data from whichever message path ran (texto, foto o audio)
let normItem = null;
try { const d = $('Extraer transcripcion').item.json; if (d && d.chat_id) normItem = d; } catch(e) {}
if (!normItem) {
  try { const d = $('Normalizar foto').item.json; if (d && d.chat_id) normItem = d; } catch(e) {}
}
if (!normItem) {
  try { const d = $('Normalizar texto').item.json; if (d && d.chat_id) normItem = d; } catch(e) {}
}
if (!normItem) normItem = {};

const chat_id = String(normItem.chat_id || '');
const user_text = normItem.user_text || '';
const has_image = normItem.has_image || false;
const has_audio = normItem.has_audio || false;
const message_id = normItem.message_id;
const first_name = normItem.first_name || '';

let active_file_id = 'none', active_file_name = 'ninguno', active_sheet = 'Hoja 1';
try {
  const row = $input.item.json;
  if (row && row.active_file_id && row.active_file_id !== 'none') {
    active_file_id = row.active_file_id;
    active_file_name = row.active_file_name || 'ninguno';
    active_sheet = row.active_sheet || 'Hoja 1';
  }
} catch(e) {}

return { json: { chat_id, user_text, has_image, has_audio, message_id, first_name, active_file_id, active_file_name, active_sheet } };

let text = $input.item.json.output || '';

// Fallback if agent returned empty
if (!text.trim()) {
  text = 'Lo siento, ocurrio un problema al procesar tu mensaje. Por favor intentalo de nuevo.';
}

// Strip Drive IDs from markdown table columns
const lines = text.split('\n');
const result = [];
let dropCols = [];
for (const line of lines) {
  if (!line.includes('|')) { dropCols = []; result.push(line); continue; }
  const cells = line.split('|');
  if (dropCols.length === 0) {
    dropCols = cells.map((c,i) => /^\s*(ID|ID del archivo|File ID|Identificador)\s*$/i.test(c.trim()) ? i : -1).filter(i => i >= 0);
  }
  const dataDrop = cells.map((c,i) => /^[A-Za-z0-9_\-]{25,}$/.test(c.trim()) ? i : -1).filter(i => i >= 0);
  const allDrop = new Set([...dropCols, ...dataDrop]);
  result.push(allDrop.size > 0 ? cells.filter((_,i) => !allDrop.has(i)).join('|') : line);
}
text = result.join('\n');

// Strip IDs in parentheses
text = text.replace(/\s*\(ID:\s*`?[A-Za-z0-9_\-]{20,}`?\)/g, '');
// Strip standalone Drive IDs inline
text = text.replace(/(^|[\s|,])([A-Za-z0-9_\-]{28,})(?=[\s|,.]|$)/gm, '$1');
// Strip n8n footer
text = text.replace(/\s*This message was sent automatically with[\s\S]*?(\n|$)/gi, '');
text = text.replace(/\s*Sent automatically with n8n[\s\S]*?(\n|$)/gi, '');
// Misc cleanup
text = text.replace(/,?\s*indicando su nombre o ID\.?/gi, '.');
text = text.replace(/,?\s*o su ID\.?/gi, '.');
text = text.replace(/\|\s*\|/g, '|');

// Escape underscores outside *bold* to avoid Telegram Markdown errors
text = text.replace(/\*[^*]+\*/g, m => '\x00' + m + '\x00');
text = text.replace(/_/g, '\\_');
text = text.replace(/\x00\*([^*]+)\*\x00/g, '*$1*');

text = text.replace(/  +/g, ' ').replace(/\n{3,}/g, '\n\n').trim();
return { json: { output: text } };

// Get transcription from Gemini response
const geminiResp = $input.item.json;
let transcription = "";
try {
  transcription = geminiResp.candidates?.[0]?.content?.parts?.[0]?.text || "";
  transcription = transcription.trim();
} catch(e) {}

// Get message info from Telegram Trigger
const tgMsg = $("Telegram Trigger").item.json.message || {};

if (!transcription) {
  transcription = "No pude transcribir el audio. Por favor envia un mensaje de texto.";
}

return {
  json: {
    chat_id: String(tgMsg.chat?.id || ""),
    message_id: tgMsg.message_id || 0,
    user_text: transcription,
    has_image: false,
    has_audio: true,
    first_name: tgMsg.from?.first_name || ""
  }
};

